import{_ as s,c as a,o as i,b as d}from"./app.b5c11ed0.js";const u='{"title":"\u0413\u043B\u0430\u0432\u0430 3","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 3","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-10-30T00:00:00.000Z"},"headers":[{"level":2,"title":"\u0422\u0440\u0435\u0442\u044C\u044F \u0433\u043B\u0430\u0432\u0430","slug":"\u0442\u0440\u0435\u0442\u044C\u044F-\u0433n\u0430\u0432\u0430"}],"relativePath":"texts/malini-vijayottara/3/index.md"}',e={},n=d('<h2 id="\u0442\u0440\u0435\u0442\u044C\u044F-\u0433n\u0430\u0432\u0430" tabindex="-1">\u0422\u0440\u0435\u0442\u044C\u044F \u0433\u043B\u0430\u0432\u0430 <a class="header-anchor" href="#\u0442\u0440\u0435\u0442\u044C\u044F-\u0433n\u0430\u0432\u0430" aria-hidden="true">#</a></h2><div class="stanza"><a href="#s3.1" id="s3.1" class="num">3.1</a><p>\u041D\u0430 \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0442\u0430\u043A (\u0428\u0438\u0432\u043E\u0439), \u0422\u0432\u043E\u0440\u044F\u0449\u0438\u043C \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0412\u0435\u043B\u0438\u043A\u0430\u044F \u0411\u043E\u0433\u0438\u043D\u044F \u0432\u043D\u043E\u0432\u044C \u043F\u043E\u043A\u043B\u043E\u043D\u0438\u043B\u0430\u0441\u044C \u0412\u043B\u0430\u0434\u044B\u043A\u0435 \u041C\u0438\u0440\u0430, \u0438, \u043E\u0431\u0440\u0430\u0442\u0438\u0432\u0448\u0438\u0441\u044C \u0441 \u0440\u0435\u0447\u044C\u044E, \u0441\u043A\u0430\u0437\u0430\u043B\u0430.</p></div><div class="stanza"><a href="#s3.2" id="s3.2" class="num">3.2</a><p>\u0418\u043C\u0435\u043D\u043D\u043E \u0442\u0430\u043A, \u0438 \u043D\u0435 \u0438\u043D\u0430\u0447\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u044D\u0442\u043E (\u041C\u0438\u0440\u043E\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435), \u043E \u0412\u0435\u043B\u0438\u043A\u0438\u0439 \u0411\u043E\u0433, \u043A\u0430\u043A \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0442\u043E\u0431\u043E\u0439.</p></div><div class="stanza"><a href="#s3.3" id="s3.3" class="num">3.3</a><p>\u0424\u043E\u0440\u043C\u0430 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0428\u0438\u0432\u044B, \u0435\u0441\u0442\u044C \u0431\u0435\u0437\u0437\u0432\u0443\u0447\u043D\u0430\u044F \u0420\u0435\u0447\u044C, \u043E \u043D\u0435\u0439 \u043F\u043E \u0422\u0432\u043E\u0435\u0439 \u043C\u0438\u043B\u043E\u0441\u0442\u0438 \u044F \u0443\u0441\u043B\u044B\u0448\u0430\u0442\u044C \u0436\u0435\u043B\u0430\u044E.</p></div><div class="stanza"><a href="#s3.4" id="s3.4" class="num">3.4</a><p>\u041D\u0430 \u0441\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0435 \u0442\u0430\u043A \u0412\u0435\u043B\u0438\u043A\u043E\u0439 \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0435\u0439 (\u043E\u0442\u0432\u0435\u0442\u0438\u043B) \u0425\u0430\u0440\u0430, \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0431\u043B\u0430\u0433\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439: \xAB\u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u043C\u0430\u044F \u0420\u0435\u0447\u044C \u0435\u0441\u0442\u044C \u043C\u0430\u043D\u0442\u0440\u044B, \u043F\u0435\u0440\u0435\u0434\u0430\u0432\u0430\u0435\u043C\u044B\u0435 \u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0435\u0439.</p></div><div class="stanza"><a href="#s3.5" id="s3.5" class="num">3.5</a><p>\u0422\u0430, \u041A\u043E\u0442\u043E\u0440\u0430\u044F \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0428\u0430\u043A\u0442\u0438 \u0422\u0432\u043E\u0440\u0446\u0430 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439, \u0415\u0434\u0438\u043D\u043E\u0439 \u0441 \u041D\u0438\u043C, \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0415\u0433\u043E \u0412\u043E\u043B\u0435\u0439, \u0436\u0435\u043B\u0430\u044E\u0449\u0435\u0439 \u0442\u0432\u043E\u0440\u0438\u0442\u044C.</p></div><div class="stanza"><a href="#s3.6" id="s3.6" class="num">3.6</a><p>\u0412\u043E\u0438\u0441\u0442\u0438\u043D\u0443 \u041E\u043D\u0430 \u0415\u0434\u0438\u043D\u0430\u044F \u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F. \u0412\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E \u041D\u0435\u0439, \u043A\u0430\u043A \u043E\u043D\u0430 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442. \u041E\u043D\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0439 (\u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E), \u043D\u0435 \u0438\u043D\u0430\u0447\u0435, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s3.7-11" id="s3.7-11" class="num">3.7-11</a><p>\u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F \u0432\u043E \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 \u041E\u043D\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0434\u0436\u043D\u0430\u043D\u0430 \u0448\u0430\u043A\u0442\u0438</em>. \u042D\u0442\u0430 \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C (\u041A\u043E\u0442\u043E\u0440\u0430\u044F \u0434\u0430 \u0431\u0443\u0434\u0435\u0442!) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u044E\u0449\u0435\u0439 \u043A\u0430\u0436\u0434\u043E\u0435 \u0441\u043B\u043E\u0432\u043E \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435. \u041E\u043D\u0430 \u0434\u0432\u043E\u044F\u043A\u0430 \u0438 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u0430. \u0427\u0435\u0440\u0435\u0437 \u043D\u0435\u0435 \u0438 \u043F\u043E\u0434 \u0415\u0435 \u0432\u043E\u0437\u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0435\u043C (\u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442) \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u0438\u0435 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u043C\u0438. (\u041E\u043D\u0430), \u0412\u043B\u0430\u0434\u044B\u0447\u0438\u0446\u0430 \u0420\u0435\u0447\u0438, \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F \u043A\u0430\u043C\u043D\u044E \u0447\u0438\u043D\u0442\u0430\u043C\u0430\u043D\u0438, \u043F\u043E\u044F\u0432\u043B\u044F\u044F\u0441\u044C, \u0434\u0440\u043E\u0431\u0438\u0442\u0441\u044F \u0432 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 \u043C\u0430\u0442\u0440\u0438\u043A\u0438 \u043A\u0430\u043A \u0434\u0432\u0435, \u0434\u0435\u0432\u044F\u0442\u044C \u0438 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442. \u041C\u0430\u043B\u0438\u043D\u0438 \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438 \u0438 \u0431\u0438\u0434\u0436\u0435\u0439, \u0434\u0432\u043E\u044F\u043A\u043E\u0439 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0431\u0438\u0434\u0436\u0438 \u0438 \u0439\u043E\u043D\u0438. \u0419\u043E\u043D\u0438 \u0435\u0441\u0442\u044C \u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u043D\u0430 \u0434\u0435\u0432\u044F\u0442\u044C \u0440\u044F\u0434\u043E\u0432 (\u0431\u0443\u043A\u0432) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E \u0441\u043B\u043E\u0433\u0430 \u041A\u0410. \u0414\u0435\u043B\u044F\u0441\u044C \u0432 \u043A\u0430\u0436\u0434\u043E\u043C \u0440\u044F\u0434\u0435 (\u0432\u0430\u0440\u0433\u0435) \u043D\u0430 \u043F\u044F\u0442\u044C, \u043E\u043D\u0430 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 (\u0431\u0443\u043A\u0432).</p></div><div class="stanza"><a href="#s3.12" id="s3.12" class="num">3.12</a><p>\u0411\u0438\u0434\u0436\u0435\u0439 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0428\u0438\u0432\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438. \u0412\u0441\u044F \u0420\u0435\u0447\u044C \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F (\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C) \u0428\u0438\u0432\u044B \u0438 \u0428\u0430\u043A\u0442\u0438.</p></div><div class="stanza"><a href="#s3.13" id="s3.13" class="num">3.13</a><p>(\u0428\u0438\u0432\u0430) \u0435\u0441\u0442\u044C \u0432\u043E\u0441\u0435\u043C\u044C \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u0445 \u0440\u044F\u0434\u043E\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410\u0433\u0445\u043E\u0440\u044B. \u0428\u0430\u043A\u0442\u0438 \u0436\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u0432\u043E\u0441\u0435\u043C\u044C (\u0432\u0430\u0440\u0433), \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041C\u0430\u0445\u0435\u0448\u0432\u0430\u0440\u0438.</p></div><div class="stanza"><a href="#s3.14" id="s3.14" class="num">3.14</a><p>(\u0412\u043E\u0441\u0435\u043C\u044C \u044D\u0442\u0438\u0445 \u0428\u0430\u043A\u0442\u0438 \u044D\u0442\u043E): \u041C\u0430\u0445\u0435\u0448\u0438, \u0411\u0440\u0430\u0445\u043C\u0438, \u041A\u0430\u0443\u043C\u0430\u0440\u0438, \u0412\u0430\u0439\u0448\u043D\u0430\u0432\u0438, \u0410\u0439\u043D\u0434\u0440\u0438, \u0419\u0430\u043C\u0439\u0430, \u0427\u0430\u043C\u0443\u043D\u0434\u0430 \u0438 \u0419\u043E\u0433\u0435\u0448\u0438.</p></div><div class="stanza"><a href="#s3.15" id="s3.15" class="num">3.15</a><p>\u0415\u0435 \u0447\u0438\u0441\u043B\u043E - \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442. \u0427\u0435\u0440\u0435\u0437 \u0420\u0435\u0447\u044C \u0420\u0443\u0434\u0440 \u0432\u044B\u0440\u0430\u0436\u0430\u0435\u0442\u0441\u044F \u0412\u044B\u0441\u0448\u0438\u0439 \u0432\u043B\u0430\u0434\u044B\u043A\u0430.</p></div><div class="stanza"><a href="#s3.16" id="s3.16" class="num">3.16</a><p>\u0423 \u043D\u0438\u0445 \u0442\u0430\u043A\u043E\u0435 \u0436\u0435 \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u043E \u0428\u0430\u043A\u0442\u0438. \u041F\u043E\u0432\u0435\u0434\u0430\u044E, \u043E \u043D\u0438\u0445 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u044D\u0442\u043E.</p></div><div class="stanza"><a href="#s3.17-19" id="s3.17-19" class="num">3.17-19</a><p>\u0410\u043C\u0440\u0438\u0442\u0430, \u0410\u043C\u0440\u0438\u0442\u0430\u043F\u0443\u0440\u043D\u0430, \u0410\u043C\u0440\u0438\u0442\u0430\u0431\u0445\u0430\u0432\u0430, \u0410\u043C\u0440\u0438\u0442\u0430\u0434\u0440\u0430\u0432\u0430, \u0410\u043C\u0440\u0438\u0442\u0430\u0443\u0433\u0445\u0430, \u0410\u043C\u0440\u0438\u0442\u043E\u0440\u043C\u0438, \u0410\u043C\u0440\u0438\u0442\u0430\u0441\u0439\u0430\u043C\u0440\u0438\u0442\u0430\u0442\u0430\u043D\u0443, \u0410\u043C\u0440\u0438\u0442\u0430\u0441\u0435\u0447\u0430\u043D\u0430, \u0422\u0430\u043D\u043C\u0443\u0440\u0442\u0438, \u0410\u043C\u0440\u0438\u0442\u0435\u0448\u0430, \u0421\u0430\u0440\u0432\u0430\u043C\u0440\u0438\u0442\u0430\u0434\u0445\u0430\u0440\u0430. \u042D\u0442\u0438 \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0420\u0443\u0434\u0440\u0430 \u0431\u0438\u0434\u0436\u0430\u043C\u0438.</p></div><div class="stanza"><a href="#s3.20-25" id="s3.20-25" class="num">3.20-25</a><p>\u0422\u0440\u0438\u0434\u0446\u0430\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435: \u0414\u0436\u0430\u0439\u0430, \u0412\u0438\u0434\u0436\u0430\u0439\u0430,\u0414\u0436\u0430\u0439\u0430\u043D\u0442\u0430, \u0410\u043F\u0430\u0440\u0430\u0434\u0436\u0438\u0442\u0430, \u0421\u0443\u0434\u0436\u0430\u0439\u0430, \u0414\u0436\u0430\u0439\u0430\u0440\u0443\u0434\u0440\u0430, \u0414\u0436\u0430\u0439\u0430\u043A\u0438\u0440\u0442\u0438, \u0414\u0436\u0430\u0439\u0430\u0432\u0430\u0445\u0430, \u0414\u0436\u0430\u0439\u0430\u043C\u0443\u0440\u0442\u0438, \u0414\u0436\u0430\u0439\u043E\u0442\u0441\u0430\u0445\u0430, \u0414\u0436\u0430\u0439\u0430\u0434\u0430, \u0414\u0436\u0430\u0439\u0430\u0432\u0430\u0440\u0434\u0445\u0430\u043D\u0430, \u0411\u0430\u043B\u0430, \u0410\u0442\u0438\u0431\u0430\u043B\u0430, \u0411\u0430\u043B\u0430\u0431\u0445\u0430\u0434\u0440\u0430, \u0411\u0430\u043B\u0430\u043F\u0440\u0430\u0434\u0430, \u0411\u0430\u043B\u0430\u0432\u0430\u0445\u0430, \u0411\u0430\u043B\u0430\u0432\u0430\u043D, \u0411\u0430\u043B\u0430\u0434\u0430\u0442\u0430, \u0411\u0430\u043B\u0435\u0448\u0432\u0430\u0440\u0430, \u041D\u0430\u043D\u0434\u0430\u043D\u0430, \u0421\u0430\u0440\u0432\u0430\u0442\u043E\u0431\u0445\u0430\u0434\u0440\u0430, \u0411\u0445\u0430\u0434\u0440\u0430\u043C\u0443\u0440\u0442\u0438, \u0428\u0438\u0432\u0430\u043F\u0440\u0430\u0434\u0430, \u0421\u0443\u043C\u0430\u043D\u0430, \u0421\u043F\u0440\u0438\u0445\u0430\u043D\u0430, \u0414\u0443\u0440\u0433\u0430, \u0411\u0445\u0430\u0434\u0440\u0430\u043A\u0430\u043B\u0430, \u041C\u0430\u043D\u043E\u0433\u0430, \u041A\u0430\u0443\u0448\u0438\u043A\u0430, \u041A\u0430\u043B\u0430\u0432\u0438\u0448\u0432\u0435\u0448\u0430, \u0421\u0443\u0448\u0438\u0432\u0430, \u041A\u043E\u043F\u0430\u0432\u0430\u0440\u0434\u0445\u0430\u043D\u0430. \u042D\u0442\u0438 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0436\u0435\u043D\u0441\u043A\u0438\u043C\u0438 (\u0434\u0440\u043E\u0431\u043D\u044B\u043C\u0438) \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0428\u0430\u043A\u0442\u0438. \u0427\u0438\u0441\u043B\u043E \u0441\u043B\u043E\u0432 \u043F\u043E\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u0445 \u0431\u0438\u0434\u0436\u0435\u0439 \u0438 \u0439\u043E\u043D\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0445 \u0432 \u0420\u0443\u0434\u0440\u0435 \u0438 \u0428\u0430\u043A\u0442\u0438 \u043D\u0435\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u0438\u0437-\u0437\u0430 \u0438\u0445 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0441\u0442\u0438.</p></div><div class="stanza"><a href="#s3.26" id="s3.26" class="num">3.26</a><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0432\u044B\u043D\u0430\u0448\u0438\u0432\u0430\u043D\u0438\u044E \u0441\u043C\u044B\u0441\u043B\u0430 \u0432\u0441\u0435\u0445 \u043F\u0438\u0441\u0430\u043D\u0438\u0439 \u043F\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0412\u043E\u043B\u0435 \u0412\u0435\u0440\u0445\u043E\u0432\u043D\u044B\u0439 \u0412\u043B\u0430\u0434\u044B\u043A\u0430 \u043E\u0441\u043E\u0437\u043D\u0430\u043B \u0421\u0435\u0431\u044F, \u043A\u0430\u043A \u0410\u0433\u0445\u043E\u0440\u0443.</p></div><div class="stanza"><a href="#s3.27" id="s3.27" class="num">3.27</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u043E\u043C\u0443, \u0431\u0443\u0434\u0443\u0447\u0438 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u043D\u044B\u043C \u043E\u043D \u043F\u0440\u043E\u044F\u0432\u0438\u043B \u0447\u0435\u0440\u0435\u0437 \u0441\u0432\u043E\u0438 \u0428\u0430\u043A\u0442\u0438 \u0439\u043E\u043D\u0438. (\u0417\u0430\u0442\u0435\u043C) \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u0441\u043E\u0442\u0432\u043E\u0440\u0438\u043B \u0448\u0440\u0443\u0442\u0438 \u043F\u043E \u043A\u043E\u043B\u0438\u0447\u0435\u0441\u0442\u0432\u0443 \u0432\u0430\u0440\u043D.</p></div><div class="stanza"><a href="#s3.28" id="s3.28" class="num">3.28</a><p>\u041A\u0430\u0436\u0434\u0430\u044F \u0438\u0437 \u043D\u0438\u0445 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0435\u0439 \u0432\u043B\u0430\u0434\u044B\u043A-\u0441\u0430\u0434\u0445\u0430\u043A\u043E\u0432 \u0441 \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C\u044E, \u043D\u0435 \u0438\u043D\u0430\u0447\u0435 \u043E \u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0433\u0435\u0440\u043E\u044F\u043C\u0438!</p></div><div class="stanza"><a href="#s3.29" id="s3.29" class="num">3.29</a><p>\u0418\u043C\u0438 \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E, \u0432\u043D\u043E\u0432\u044C \u0438 \u0432\u043D\u043E\u0432\u044C, \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442\u0441\u044F \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u0430\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0431\u043E\u0433\u0430\u043C\u0438 \u0438 \u0434\u0435\u043C\u043E\u043D\u0430\u043C\u0438, \u0412\u0435\u0434\u044B \u0438 \u043F\u0438\u0441\u0430\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s3.30" id="s3.30" class="num">3.30</a><p>\u0425\u043E\u0442\u044F \u0412\u0435\u043B\u0438\u043A\u0438\u0435 \u0434\u0443\u0445\u043E\u043C \u0428\u0438\u0432\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438 \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u044B, (\u043E\u0442 \u043D\u0438\u0445) \u0438\u0437-\u0437\u0430 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438 \u043A \u0434\u0435\u043B\u0435\u043D\u0438\u044E \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432, \u043E \u0412\u0435\u043B\u0438\u043A\u0430\u044F \u0414\u0435\u0432\u0438!</p></div><div class="stanza"><a href="#s3.31-38" id="s3.31-38" class="num">3.31-38</a><p>\u0420\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u044F\u0441\u044C \u0432 \u043E\u0431\u044A\u0435\u043A\u0442\u0430\u0445, \u0434\u0443\u0448\u0438 \u043F\u0430\u0434\u0430\u044E\u0442 \u0432\u0441\u0435 \u043D\u0438\u0436\u0435 \u0438 \u043D\u0438\u0436\u0435. \u0420\u0443\u0434\u0440\u044B \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u044F \u0444\u043E\u0440\u043C\u044B \u0434\u0443\u0448 \u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F \u043D\u0438\u0437\u0448\u0438\u043C\u0438 (\u0430\u043F\u0430\u0440\u0430) \u0413\u0445\u043E\u0440\u0430\u0442\u0430\u043C\u0430. \u0422\u0435, \u043A\u0442\u043E, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u043C, \u0440\u043E\u0436\u0434\u0430\u044E\u0442\u0441\u044F, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0435 \u0441 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430\u043C\u0438 \u0441\u043C\u0435\u0448\u0430\u043D\u043D\u043E\u0439 \u043A\u0430\u0440\u043C\u044B, \u043D\u043E \u043E\u0431\u0440\u0430\u0449\u0430\u044E\u0442\u0441\u044F \u043A \u043F\u0443\u0442\u0438 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u0440\u0435\u0434\u043D\u0438\u043C\u0438 (\u043F\u0430\u0440\u0430\u0430\u043F\u0430\u0440\u0430) \u0413\u0445\u043E\u0440\u0430. \u0412\u044B\u0441\u0448\u0438\u043C\u0438 (\u043F\u0430\u0440\u0430) \u0413\u0445\u043E\u0440\u0430 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0442\u0435, \u043A\u0442\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u0440\u0435\u0434\u044B\u0434\u0443\u0449\u0438\u043C \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u044F\u043C (\u043E\u0431\u0440\u0435\u0442\u0430\u044E\u0442) \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0435, \u0434\u0430\u044E\u0449\u0435\u0435 \u043F\u043B\u043E\u0434 \u043E\u0431\u0438\u0442\u0435\u043B\u0438 \u0428\u0438\u0432\u044B. (\u041E\u043D\u0438) \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043A\u0430\u043A \u0428\u0438\u0432\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438. \u0422\u0435 (\u0438\u0437 \u043D\u0438\u0445 \u043A\u0442\u043E) \u0441\u0442\u043E\u0439\u043A\u0438 \u0432 \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u0438 \u0430\u043D\u0443 (\u044D\u043C\u043F\u0438\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u042F), \u0442\u0435 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0435\u0434\u0438\u043D\u044B\u043C\u0438 \u0441 \u0428\u0430\u043C\u0431\u0443 \u0438 \u0428\u0430\u043A\u0442\u0438, \u043E \u0428\u0430\u043D\u043A\u0430\u0440\u0438! \u0414\u043B\u044F \u043D\u0438\u0445, \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0445 \u043C\u0430\u043D\u0442\u0440\u0435 \u0438 \u0442\u0430\u043D\u0442\u0440\u0435 \u0440\u0430\u0434\u0438 \u043E\u0431\u0440\u0435\u0442\u0435\u043D\u0438\u044F \u0436\u0435\u043B\u0430\u043D\u043D\u043E\u0433\u043E \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0438\u043D\u043E\u0435 \u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0420\u0435\u0447\u0438. \u041F\u0443\u0441\u0442\u044C \u043F\u0440\u0438 \u043E\u0431\u0440\u044F\u0434\u0435 \u043D\u044C\u044F\u0441\u044B \u0438 \u043F\u0440\u0438 \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0438\u0438 \u043E\u0441\u043E\u0431\u043E\u0433\u043E \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u043C\u0430\u043D\u0442\u0440\u0443 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442 (\u043D\u0430 \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E) \u0442\u0435\u043B\u043E \u0428\u0430\u043A\u0442\u0438, \u041C\u0430\u043B\u0438\u043D\u0438, \u0440\u0430\u0437\u0431\u0438\u0442\u043E\u0435 \u0439\u043E\u043D\u0438. \u041D\u0430 \u043C\u0430\u043A\u0443\u0448\u043A\u0443 (\u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0441\u043B\u043E\u0433) \u041D\u0410, \u043D\u0430 \u0442\u0435\u043C\u044F \u0441\u043B\u043E\u0433\u0438 \u0420 \u0420 \u041B \u041B, \u0441\u043B\u043E\u0433 \u0422\u0425\u0410 - \u043D\u0430 \u043B\u043E\u0431, \u0427\u0410 \u0438 \u0422\u0425\u0410 - \u043D\u0430 \u0433\u043B\u0430\u0437\u0430, \u043D\u0430 \u043D\u043E\u0437\u0434\u0440\u0438 \u043D\u0430\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u041D\u0423, \u043D\u0430 \u0443\u0448\u0438 - \u041D\u0423. (\u0421\u043B\u043E\u0433) \u0411\u0410, \u041A\u0410 \u0432\u0430\u0440\u0433\u0443 \u0418 \u0438 \u0410 \u043D\u0430\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u043D\u0430 \u0440\u043E\u0442 \u044F\u0437\u044B\u043A \u0438 \u0437\u0443\u0431\u044B. (\u0421\u043B\u043E\u0433\u0438) \u0412\u0410, \u0411\u0425\u0410, \u0419\u0410 (\u043D\u0430\u043D\u043E\u0441\u044F\u0442\u0441\u044F) \u0441 \u043F\u0440\u0430\u0432\u043E\u0439 (\u0441\u0442\u043E\u0440\u043E\u043D\u044B) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u043E\u0442 \u0448\u0435\u0438, \u043D\u0430 \u0440\u0443\u043A\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0414\u0410 \u0438 \u0414\u0425\u0410.</p></div><div class="stanza"><a href="#s3.39" id="s3.39" class="num">3.39</a><p>\u041D\u0430 \u043B\u0430\u0434\u043E\u043D\u0438 \u0422\u0425\u0410, \u043D\u0430 \u0414\u0416\u0425\u0410 \u0438 \u0414\u0416\u0410 \u043D\u0430 \u043F\u0430\u043B\u044C\u0446\u0430\u0445, \u0414\u0416\u0420\u0410 \u0438 \u0422\u0410 \u043D\u0430 \u0444\u0430\u043B\u0430\u043D\u0433\u0430\u0445 (?), \u0428\u0410 \u0438 \u041B\u0410 (\u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u043D\u0430 \u0441\u043E\u0441\u043A\u0430\u0445 \u0438 \u0433\u0440\u0443\u0434\u0438 \u044D\u0442\u043E \xAB\u0434\u0436\u0438\u0432\u0430\xBB \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0430\u044F \u0441 <em>\u0432\u0438\u0441\u0430\u0440\u0433\u043E\u0439</em>.</p></div><div class="stanza"><a href="#s3.40" id="s3.40" class="num">3.40</a><p>\u0414\u0430\u043B\u0435\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u0430\u043D\u0430, (\u0441\u043B\u043E\u0433\u0438) \u0438 \u041A\u0428\u0410 \u0438 \u0428\u0410 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0435 \u0432 \u043F\u0443\u043F\u043A\u0435 \u0438 \u0436\u0438\u0432\u043E\u0442\u0435. (\u0421\u043B\u043E\u0433\u0438) \u041C\u0410, \u0428\u0410, \u0422\u0410, (\u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u043F\u043E\u043F\u0430\u0440\u043D\u043E \u043D\u0430 \u0431\u0435\u0434\u0440\u0430, \xAB\u0442\u0430\u0439\u043D\u043E\u0435 \u043C\u0435\u0441\u0442\u043E\xBB, \u0436\u0438\u0432\u043E\u0442 \u0438 \u043A\u043E\u043B\u0435\u043D\u0438.</p></div><div class="stanza"><a href="#s3.41" id="s3.41" class="num">3.41</a><p>\u0421\u043B\u043E\u0433\u0438 \u042D, \u0410\u0419, \u041A\u0410, \u0420\u0410, \u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \u043D\u0430 \u043B\u043E\u0434\u044B\u0436\u043A\u0438, \u043D\u0430 \u0441\u0442\u043E\u043F\u044B (\u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F) \u0414\u0410 \u0438 \u041F\u0425\u0410. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043A\u0430\u043A \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0442\u0441\u044F \u0432\u0438\u0434\u044C\u044F \u043C\u0430\u043D\u0442\u0440\u044B.</p></div><div class="stanza"><a href="#s3.42-43" id="s3.42-43" class="num">3.42-43</a><p>\u0412 \u043C\u0435\u0441\u0442\u0435 \u0441 \u0431\u0438\u043D\u0434\u0443 (\u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u044F\u0442\u0441\u044F) \xAB\u043F\u0440\u0430\u0432\u043E\u0435 \u043A\u043E\u043B\u0435\u043D\u043E\xBB, (\u041A\u0428\u0410) \u0437\u0430\u0442\u0435\u043C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \xAB\u0440\u0435\u0447\u044C\xBB (\u0410\u0419\u041C), \u0437\u0430\u0442\u0435\u043C \u0441 \xAB\u043A\u043E\u043B\u0435\u043D\u043E\u043C\xBB \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0441\u0432\u044F\u0437\u0430\u0442\u044C \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E \u0438 \u0434\u0435\u0441\u044F\u0442\u0443\u044E (\u0433\u043B\u0430\u0441\u043D\u044B\u0435 \u0423, \u0438 \u042D).(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438) \xAB\u043F\u0430\u043B\u043A\u0443\xBB \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u043D\u0443\u044E \u0441 \xAB\u043F\u0440\u0430\u0432\u044B\u043C \u043A\u043E\u043B\u0435\u043D\u043E\u043C\xBB, \xAB\u043F\u0440\u0430\u043D\u0443\xBB \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0443\u044E \u0441 \xAB\u043F\u0430\u043B\u043A\u043E\u0439\xBB, \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E \xAB\u0436\u0438\u0440\xBB, \xAB\u043F\u0430\u043B\u043A\u0443\xBB, \xAB\u043A\u043E\u043B\u0435\u043D\u043E\xBB, \xAB\u0434\u0432\u0430\u0436\u0434\u044B\u0440\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0433\u043E\xBB \u0438 \xAB\u043F\u0430\u043B\u043A\u0443\xBB.</p></div><div class="stanza"><a href="#s3.42-52" id="s3.42-52" class="num">3.42-52</a><p>\u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u0441\u044F \xAB\u043F\u0440\u0430\u043D\u0430\xBB \u0432 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0438 \u0441 <em>\u0431\u0438\u043D\u0434\u0443</em> \u0437\u0430\u0442\u0435\u043C \u043A\u0430\u043A \u0440\u0430\u043D\u0435\u0435 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0434\u0435\u0441\u044F\u0442\u044B\u0439 (\u0441\u043B\u043E\u0433), \u043E\u0434\u043D\u0430 \xAB\u043F\u0430\u043B\u043A\u0430\xBB, \xAB\u044F\u0433\u043E\u0434\u0438\u0446\u044B\xBB \u0441 \xAB\u0434\u0430\u043A\u0448\u0438\u043D\u0430 \u043C\u0443\u0434\u0440\u043E\u0439\xBB, \u0432\u043E\u0442\u043E\u0440\u043E\u0439 \u0441\u043B\u043E\u0433 \u0441 \xAB\u0434\u0432\u0430\u0436\u0434\u044B \u0440\u043E\u0436\u0434\u0435\u043D\u043D\u044B\u043C\xBB \u0438 \xAB\u044F\u0437\u044B\u043A\u043E\u043C\xBB, \u0441 \xAB\u043D\u043E\u0437\u0434\u0440\u0435\u044E\xBB \xAB\u043F\u0440\u0430\u0432\u0430\u044F \u043C\u0430\u043A\u0443\u0448\u043A\u0430\xBB, \u0437\u0430\u0442\u0435\u043C \xAB\u044F\u0433\u043E\u0434\u0438\u0446\u044B\xBB, \u0437\u0430\u0442\u0435\u043C \xAB\u043C\u0430\u043A\u0443\u0448\u043A\u0430\xBB, \xAB\u0436\u0438\u0432\u043E\u0442\xBB, \xAB\u043F\u0440\u0430\u0432\u043E\u0435 \u043A\u043E\u043B\u0435\u043D\u043E\xBB, \xAB\u0443\u0445\u043E\xBB, \xAB\u0433\u043E\u0440\u043B\u043E\xBB. \u041D\u0430 \xAB\u044F\u0433\u043E\u0434\u0438\u0446\u044B\xBB \u043D\u0430\u043B\u0430\u0433\u0430\u0435\u0442\u0441\u044F \xAB\u0441\u0435\u0440\u0434\u0446\u0435\xBB, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \xAB\u044F\u0437\u044B\u043A\u043E\u043C\xBB. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438 \xAB\u0443\u0441\u0442\u0430\xBB \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \xAB\u043A\u043E\u043B\u0435\u043D\u043E\u043C\xBB \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \xAB\u043F\u0440\u0430\u043D\u044B\xBB, \xAB\u0442\u0440\u0435\u0437\u0443\u0431\u0435\u0446\xBB, \xAB\u043F\u0430\u043B\u043A\u0443\xBB, \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u0443\u044E (\u0433\u043B\u0430\u0441\u043D\u0443\u044E), \u0437\u0430\u0442\u0435\u043C \u043F\u0435\u0440\u0432\u0443\u044E, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0443\u044E \u043F\u0430\u0440\u043D\u043E. \u041F\u043E\u0441\u043B\u0435 \u044D\u0442\u043E\u0433\u043E, \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u0441\u044F \xAB\u043B\u0435\u0432\u0430\u044F \u0441\u0442\u043E\u043F\u0430\xBB \u0438 \xAB\u0443\u043F\u0430\u0432\u0448\u0430\u044F \u043A\u0430\u043F\u0430\u043B\u0430\xBB \u043F\u043E\u0441\u043B\u0435 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0410\u0433\u0445\u043E\u0440\u044B, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E \xAB\u0441\u0442\u043E\u043F\u044B\xBB. \u042D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u0439 (\u043F\u0430\u0440\u0430 \u0430\u043F\u0440\u0430 \u0432\u0438\u0434\u0439\u0435\u0439 ). \u0422\u0435\u043F\u0435\u0440\u044C \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442\u0441\u044F \u043D\u0438\u0437\u0448\u0430\u044F (\u0430\u043F\u0430\u0440\u0430). \u041F\u043E\u0441\u043B\u0435 \xAB\u0410\u0433\u0445\u043E\u0440\u044B\xBB \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u043C\u0435\u0441\u0442\u0438\u0442\u044C \u0432\u043D\u0430\u0447\u0430\u043B\u0435 \xAB\u043F\u0440\u0430\u043D\u0443\xBB \u0432 \u0441\u043E\u0435\u0434\u0438\u043D\u0435\u043D\u0438\u0438 \u0441 <em>\u0431\u0438\u043D\u0434\u0443</em> , \u0437\u0430\u0442\u0435\u043C, \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435, \u043F\u043E\u043C\u0435\u0449\u0430\u044E\u0442\u0441\u044F \xAB\u0441\u0442\u043E\u043F\u044B\xBB, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u041A\u0410 \u0438 \xAB<em>\u0432\u0430\u043C\u0430 \u043C\u0443\u0434\u0440\u044B</em>\xBB. \u041F\u043E\u0432\u0435\u0434\u0430\u043D\u0430 \u043D\u0438\u0437\u0448\u0430\u044F (\u0432\u0438\u0434\u0439\u0430) \u0442\u0435\u043F\u0435\u0440\u044C \u0432\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u0432\u044B\u0441\u0448\u0443\u044E \u0420\u0443\u0434\u0440\u0430 \u0428\u0430\u043A\u0442\u0438 (\u0432\u0438\u0434\u0439\u044E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043A\u043E\u0442\u043E\u0440\u043E\u0439) \u043C\u0430\u043D\u0442\u0440\u044B \u0434\u0432\u0438\u0436\u0443\u0442\u0441\u044F \u0434\u0440\u0443\u0433 \u043A \u0434\u0440\u0443\u0433\u0443 \u0441 \u043A\u0430\u0436\u0434\u044B\u043C \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435\u043C.</p></div><div class="stanza"><a href="#s3.53-56" id="s3.53-56" class="num">3.53-56</a><p>\u0422\u0435\u043B\u043E \u0442\u0440\u044F\u0441\u0435\u0442\u0441\u044F \u0438 \u043F\u0430\u0434\u0430\u0435\u0442, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u0430\u044F \u043C\u0443\u0434\u0440\u0430 \u0435\u0441\u0442\u044C \u043F\u0435\u043D\u0438\u0435, \u0440\u0435\u0432 \u0428\u0438\u0432\u044B. \u0413\u043E\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0438 \u043F\u0440\u043E\u0447\u0435\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0430\u0435\u0442\u0441\u044F \u0440\u0430\u0434\u0438 \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u0438 \u043D\u0435\u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0435\u0433\u043E. \xAB\u0414\u0436\u0438\u0432\u0443\xBB \u0441 \xAB\u043F\u0440\u0430\u0432\u044B\u043C \u043A\u043E\u043B\u0435\u043D\u043E\u043C\xBB, \u043F\u0440\u0438\u0445\u043E\u0434\u044F\u0449\u0443\u044E \u043F\u043E \u0446\u0435\u043F\u0438 \u043F\u0440\u0435\u0435\u043C\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u043D\u0435 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0434\u0430\u0432\u0430\u0442\u044C \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u043C\u0443 \u043D\u0435 \u0443\u0447\u0435\u043D\u0438\u043A\u0443, \u0430 \u0434\u0430\u0432\u0430\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0442\u043E\u043C\u0443, \u043A\u0442\u043E \u0432\u0437\u0438\u0440\u0430\u0435\u0442 \u0441 \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C\u044E \u043D\u0430 \u0442\u0440\u043E\u0438\u0445: \u0420\u0443\u0434\u0440\u0443, \u0428\u0430\u043A\u0442\u0438 \u0420\u0443\u0434\u0440\u044B \u0438 \u0423\u0447\u0438\u0442\u0435\u043B\u044F \u043A\u0430\u043A \u043D\u0430 \u0415\u0434\u0438\u043D\u043E\u0435, \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u043B\u0438\u043A\u0430\u044F!</p></div><div class="stanza"><a href="#s3.57-58" id="s3.57-58" class="num">3.57-58</a><p>\u0423\u0447\u0435\u043D\u0438\u043A \u043F\u043E\u043B\u0443\u0447\u0430\u0435\u0442 \u044D\u0442\u043E, \u043A\u043E\u0433\u0434\u0430 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D \u0423\u0447\u0438\u0442\u0435\u043B\u044C, \u043A\u043E\u0433\u0434\u0430 \u0438\u043C \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442\u0441\u044F \u0441 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C \u043F\u0440\u0438 \u043F\u043E\u043C\u043E\u0449\u0438 \u0423\u0447\u0438\u0442\u0435\u043B\u044F_ _\u0442\u0435\u043B\u043E, \u0441\u0443\u0431\u0441\u0442\u0430\u043D\u0446\u0438\u044F (\u0434\u0440\u0430\u0432\u044C\u044F), \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435, \u0447\u0438\u0441\u0442\u043E\u0442\u0430, \u0432 \u043C\u0435\u0441\u0442\u0435 \u0441 \u043A\u0430\u0440\u043C\u043E\u0439 \u0438 \u0433\u0443\u043D\u0430\u043C\u0438. \u0422\u043E\u0433\u0434\u0430 \u043E\u043D\u0430, \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F, \u0434\u0430\u0435\u0442 \u0441\u0438\u0434\u0434\u0445\u0438, \u043D\u0435 \u0438\u043D\u0430\u0447\u0435, \u041E \u041F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u0430\u044F \u0433\u0435\u0440\u043E\u044F\u043C\u0438!</p></div><div class="stanza"><a href="#s3.59" id="s3.59" class="num">3.59</a><p>\u0418\u0437 \u0447\u0430\u0441\u0442\u0438 _\u043F\u0430\u0440\u0430\u043F\u0430\u0440\u0430 _(\u0432\u0438\u0434\u0439\u0438) \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0442 \u0432\u043E\u0441\u0435\u043C\u044C \u0432\u0441\u0435\u0441\u0438\u043B\u044C\u043D\u044B\u0445 \u0439\u043E\u0433\u0438\u043D\u0438. (\u043C\u0430\u043D\u0442\u0440). \u0412 \u043D\u0438\u0445 (\u0441\u043E\u0434\u0435\u0440\u0436\u0438\u0442\u0441\u044F) \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443: \u043F\u044F\u0442\u044C, \u0448\u0435\u0441\u0442\u044C, \u043F\u044F\u0442\u044C, \u0447\u0435\u0442\u044B\u0440\u0435, \u0434\u0432\u0430, \u0442\u0440\u0438 \u0438 \u0434\u0432\u0430 \u0441\u043B\u043E\u0433\u0430.</p></div><div class="stanza"><a href="#s3.60-61" id="s3.60-61" class="num">3.60-61</a><p>\u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u0435 \u043F\u044F\u0442\u044C \u043C\u0430\u043D\u0442\u0440 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441\u043E \u0441\u043B\u043E\u0433\u043E\u043C \u041E\u041C: \u0441\u0435\u043C\u0438\u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0441\u043B\u043E\u0436\u043D\u0430\u044F, \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u043E\u0434\u043D\u043E\u0439 \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 (\u0441\u043B\u043E\u0433\u0430\u043C\u0438), \xAB\u0434\u0436\u0438\u0432\u0430\xBB \u0441 \u0448\u0435\u0441\u0442\u044C\u044E \u0434\u043E\u043B\u0433\u0438\u043C\u0438 \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438, \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E \u043F\u043E \u0440\u043E\u0434\u0443, \u0447\u043B\u0435\u043D\u044B \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u0438\u0439, \u0441 \u043F\u044F\u0442\u044C\u044E \u043A\u0440\u0430\u0442\u043A\u0438\u043C\u0438 (\u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438) \u0438 \xAB\u0443\u0441\u0442\u0430\u043C\u0438\xBB \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u0435\u0440\u0434\u0446\u0435\u043C \u0432\u0438\u0434\u0439\u0438.</p></div><div class="stanza"><a href="#s3.62" id="s3.62" class="num">3.62</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438) \u041E\u041C \u0430\u043C\u0440\u0438\u0442\u0435 \u0442\u0435\u0434\u0436\u043E\u043C\u0430\u043B\u0438\u043D\u0438 \u0421\u0412\u0410\u0425\u0410. \u042D\u0442\u043E \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0441\u043B\u043E\u0436\u043D\u0430\u044F \u043C\u0430\u043D\u0442\u0440\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0433\u043E\u043B\u043E\u0432\u043E\u044E \u0411\u0440\u0430\u0445\u043C\u044B.</p></div><div class="stanza"><a href="#s3.63-68" id="s3.63-68" class="num">3.63-68</a><p>(\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0442\u0438) \u0432\u043D\u0430\u0447\u0430\u043B\u0435 <em>\u043F\u0440\u0430\u043D\u0430\u0432\u0443</em>, \u0437\u0430\u0442\u0435\u043C <em>\u0432\u0435\u0434\u0430\u0432\u0435\u0434\u0438\u043D\u0438</em> <em>\u0445\u0443\u043C \u043F\u0445\u0430\u0442</em>. \u042D\u0442\u043E - \u0432\u043E\u0441\u044C\u043C\u0438\u0441\u043B\u043E\u0436\u043D\u0430\u044F \u0440\u0443\u0434\u0440\u0430\u043D\u0438 (\u041C\u0430\u043D\u0442\u0440\u0430) \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u043A\u0430\u043A \u0432\u0435\u0440\u0448\u0438\u043D\u0430 \u0441\u043E\u0431\u0440\u0430\u043D\u0438\u044F \u0432\u0438\u0434\u0438\u0439. (\u041F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u0441\u044F) \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043F\u0440\u0430\u043D\u0430\u0432\u044B, <em>\u0432\u0430\u0434\u0436\u0440\u0438\u043D\u0435 \u0432\u0430\u0434\u0436\u0440\u0430\u0434\u0445\u0430\u0440\u0430\u0439\u0430 \u0441\u0432\u0430\u0445\u0430</em>. \u042D\u0442\u0430 \u043E\u0434\u0438\u043D\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0441\u043B\u043E\u0436\u043D\u0430\u044F \xAB\u0431\u0440\u043E\u043D\u044F\xBB \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043C\u043D\u043E\u0433\u043E\u043F\u0440\u043E\u0441\u043B\u0430\u0432\u043B\u0435\u043D\u043D\u043E\u0439 (\u043C\u0430\u043D\u0442\u0440\u043E\u0439). ( \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438) \u0428\u041B\u0418\u041C, \u0437\u0430\u0442\u0435\u043C \u0441\u043B\u043E\u0432\u043E <em>\u043F\u0430\u0448\u0443,</em> \u0432 \u043A\u043E\u043D\u0446\u0435 - \u0425\u0423\u041C \u041F\u0425\u0410\u0422, \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 - \u041E\u041C. \u042D\u0442\u043E (\u043C\u0430\u043D\u0442\u0440\u0430) \u0438\u0437 \u0441\u0435\u043C\u0438 \u0441 \u043F\u043E\u043B\u043E\u0432\u0438\u043D\u043E\u0439 \u0441\u043B\u043E\u0433\u043E\u0432 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u043F\u0430\u0448\u0443\u043F\u0430\u0442\u0430</em>. (\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0442\u0438) \u041B\u0410, \u041A\u0428\u0410, \u0412\u0410, \u0419\u0410 \u0441 \u0434\u043E\u043B\u0433\u0438\u043C\u0438 (\u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438) \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0421\u0410, \u0425\u0410 \u0438 <em>\u0431\u0438\u043D\u0434\u0443.</em> \u0414\u043B\u044F \u044D\u0442\u043E\u0439 \u043C\u0430\u043D\u0442\u0440\u044B \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u044E\u0442\u0441\u044F \u0412\u0438\u0448\u043D\u0443 \u0438 \u041F\u0440\u0430\u0434\u0436\u0430\u043F\u0430\u0442\u0438 \u0441 \xAB\u043D\u043E\u0437\u0434\u0440\u044F\u043C\u0438\xBB \u0438 \xAB\u0432\u043E\u0434\u0430\u043C\u0438\xBB, \u0433\u043B\u0430\u0441\u043D\u044B\u0435, \u0441\u043B\u043E\u0433\u0438 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0412\u0410 \u0438 \u0442\u0440\u0435\u0442\u044C\u044F (\u0433\u043B\u0430\u0441\u043D\u0430\u044F \u0418), \xAB\u043B\u043E\u0442\u043E\u0441\xBB \u0438 \xAB\u0447\u0430\u043A\u0440\u0430\xBB. \u0418\u0442\u0430\u043A, \u043F\u043E\u0432\u0435\u0434\u0430\u043D \u0441\u043E\u043D\u043C \u041C\u0430\u0442\u0435\u0440\u0435\u0439 (\u043C\u0430\u0442\u0440\u0438 \u0433\u0430\u043D\u0430) \u0440\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0439\u043E\u0433\u0438\u043D\u043E\u0432 \u0432 \u0439\u043E\u0433\u0435. \u041E \u0447\u0435\u043C \u0435\u0449\u0435 \u0436\u0435\u043B\u0430\u0435\u0448\u044C \u0441\u043F\u0440\u043E\u0441\u0438\u0442\u044C?</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0442\u0440\u0435\u0442\u044C\u044F \u0433\u043B\u0430\u0432\u0430, (\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F) \xAB\u041F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u0435 \u043C\u0430\u043D\u0442\u0440\u044B\xBB.</p>',33),c=[n];function l(t,p,v,m,r,h){return i(),a("div",null,c)}var z=s(e,[["render",l]]);export{u as __pageData,z as default};
